{
  "$schema": "https://schema.management.azure.com/schemas/2019-09-01/policySetDefinition.json#",
  "contentVersion": "1.0.0.0",
  "name": "corp-security-baseline",
  "displayName": "Corporate Security Baseline",
  "description": "Enforces security controls across all corporate subscriptions.",
  "metadata": {
    "version": "1.0.0",
    "category": "Security"
  },
  "parameters": {
    "logAnalyticsWorkspaceId": {
      "type": "String",
      "metadata": {
        "displayName": "Log Analytics Workspace ID",
        "description": "Resource ID of the central Log Analytics workspace"
      }
    },
    "auditVmAgentEffect": {
      "type": "String",
      "defaultValue": "AuditIfNotExists",
      "allowedValues": ["AuditIfNotExists", "Disabled"],
      "metadata": { "displayName": "VM Agent Audit: Effect" }
    },
    "denyPublicStorageEffect": {
      "type": "String",
      "defaultValue": "Deny",
      "allowedValues": ["Audit", "Deny", "Disabled"],
      "metadata": { "displayName": "Public Storage: Effect" }
    }
  },
  "policyDefinitions": [
    {
      "policyDefinitionId": "/providers/Microsoft.Management/managementGroups/mg-corp/providers/Microsoft.Authorization/policyDefinitions/audit-vm-law-agent",
      "policyDefinitionReferenceId": "auditVmLawAgent",
      "parameters": {
        "logAnalyticsWorkspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" },
        "effect": { "value": "[parameters('auditVmAgentEffect')]" }
      },
      "groupNames": ["MonitoringAndLogging"]
    },
    {
      "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/34c877ad-507e-4c82-993e-3452a6e0ad3c",
      "policyDefinitionReferenceId": "denyPublicStorage",
      "parameters": {
        "effect": { "value": "[parameters('denyPublicStorageEffect')]" }
      },
      "groupNames": ["DataProtection"]
    }
  ],
  "policyDefinitionGroups": [
    { "name": "MonitoringAndLogging", "displayName": "Monitoring and Logging Controls" },
    { "name": "DataProtection", "displayName": "Data Protection Controls" }
  ]
}

// Pattern 1: Threading — initiative parameter flows to policy parameter
// Assignment provides logAnalyticsWorkspaceId, it flows into the AINE policy
{
  "policyDefinitionId": "...",
  "parameters": {
    "logAnalyticsWorkspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" }
  }
}

// Pattern 2: Hardcoded — value is fixed in the initiative, not changeable at assignment
{
  "policyDefinitionId": "...",
  "parameters": {
    "allowedLocations": { "value": ["eastus2", "westus2"] }
  }
}

// Pattern 3: Per-policy override at assignment time (built-in initiatives only)
// When assigning, override individual policy parameters using
// the policyDefinitionReferenceId as the key
// az policy assignment create --params '{
//   "effect-<referenceId>": { "value": "Disabled" }
// }'

// Best practice: expose ALL variable parameters at initiative level
// so assignments can tune behavior without modifying the definition.
// Hardcode only values that must NEVER change (e.g., your tenant's allowed regions).

resource "azurerm_policy_set_definition" "corp_baseline" {
  name         = "corp-security-baseline"
  policy_type  = "Custom"
  display_name = "Corporate Security Baseline"
  description  = "Enforces security controls across all corporate subscriptions."

  metadata = jsonencode({
    version  = "1.0.0"
    category = "Security"
  })

  parameters = jsonencode({
    logAnalyticsWorkspaceId = {
      type = "String"
      metadata = {
        displayName = "Log Analytics Workspace ID"
      }
    }
    auditVmAgentEffect = {
      type         = "String"
      defaultValue = "AuditIfNotExists"
      allowedValues = ["AuditIfNotExists", "Disabled"]
    }
  })

  policy_definition_reference {
    policy_definition_id = azurerm_policy_definition.audit_vm_law_agent.id
    reference_id         = "auditVmLawAgent"
    parameter_values     = jsonencode({
      logAnalyticsWorkspaceId = {
        value = "[parameters('logAnalyticsWorkspaceId')]"
      }
      effect = {
        value = "[parameters('auditVmAgentEffect')]"
      }
    })
    policy_group_names = ["MonitoringAndLogging"]
  }

  policy_definition_group {
    name         = "MonitoringAndLogging"
    display_name = "Monitoring and Logging Controls"
  }
}

resource "azurerm_management_group_policy_assignment" "corp_baseline" {
  name                 = "corp-baseline"
  management_group_id  = var.corp_mg_id
  policy_definition_id = azurerm_policy_set_definition.corp_baseline.id

  parameters = jsonencode({
    logAnalyticsWorkspaceId = {
      value = var.log_analytics_workspace_id
    }
    auditVmAgentEffect = {
      value = "AuditIfNotExists"
    }
  })
}
